
export const maskedUtils: any = {
  maskSymbol: {
    digitMaskSymbols: ['D', 'M', 'Y', '_']
  },
  specialSymbols: ['/', '(', ')', '-', ' ', '.', ','],
  // assuming in this method that special characters are inserted automatically and cannot occur in 'key' parameter
  charIsValid: (key: string, index: number, mask: string): boolean => {
    if (maskedUtils.isDigitSymbol(mask[index]) >= 0) {
      return !isNaN(parseInt(key, 10));
    }
    return true;
  },
  isSpecSymbol: (symbol: string): boolean => {
    return maskedUtils.specialSymbols.indexOf(symbol) >= 0;
  },
  isDigitSymbol: (symbol: string): boolean => {
    return maskedUtils.maskSymbol.digitMaskSymbols.indexOf(symbol) >= 0;
  },
  lastSymbolIsSpecial: (mask: string, currentIndex: number): boolean => {
    return mask && mask[currentIndex] && maskedUtils.isSpecSymbol(mask[currentIndex]);
  },
  addSpecialSymbols: (input: string, mask: string): string => {
    for (let i = 0; i < mask.length; i++) {
      if (maskedUtils.isSpecSymbol(mask[i]) && input.length >= i + 1 && !maskedUtils.isSpecSymbol(input[i])) {
        input = input.slice(0, i) + mask[i] + input.slice(i);
      }
    }
    return input;
  },
  addSpecialSymbolsAtEnd: (input: string, mask: string): string => {
    for (let i = mask.length; i >= 0; i--) {
      if (maskedUtils.isSpecSymbol(mask[i]) && input.length >= mask.length - i && !maskedUtils.isSpecSymbol(input[i])) {
        input = input.slice(0, input.length - i - 1) + mask[i] + input.slice(input.length - i - 1);
      }
    }
    return input;
  },
  replaceMask: (input: string, mask: string, maskPrefix: string, currencyBehavior: boolean): string => {
    if (input == null) {
      return '';
    }

    input = input.replace(maskPrefix, '');

    [...maskedUtils.maskSymbol.digitMaskSymbols, ...maskedUtils.specialSymbols].forEach((s) => {
      input = input.replaceAll(s, '');
    });

    if (!currencyBehavior) {
      input = maskedUtils.addSpecialSymbols(input, mask).slice(0, mask.length);
    } else {
      input = maskedUtils.addSpecialSymbolsAtEnd(input, mask);
      if (input.startsWith('00')) {
        input = input.slice(1, input.length);
      }
      if (input.startsWith('0') && parseInt(input[1]) > 0) {
        input = input.slice(1, input.length);
      }
    }

    return input;
  },
  specSymbolsLengthAtIndex: (mask: string, index: number) => {
    const firstSymbolIsSpec: boolean = maskedUtils.isSpecSymbol(mask[index]);
    if (!firstSymbolIsSpec) {
      return 0;
    }
    for (let i = index + 1; i < mask.length; i++) {
      if (!maskedUtils.isSpecSymbol(mask[i])) {
        return i - index;
      }
    }
  },
  fillDivider: (input: string, index: number, symbol: string): string => {
    let output: string = '';
    input = input.replaceAll(symbol, '');

    const inputLastIndex: number = input.length - 1;
    for (let i = inputLastIndex; i >= 0; i--) {
      if (i !== inputLastIndex && i !== inputLastIndex - index && (inputLastIndex - i) % index === 0) {
        output = symbol + output;
      }
      output = input[i] + output;
    }
    return output;
  }
};

export const selectAllTextBoxWithDelay  = (target: HTMLInputElement): void => {
  setTimeout(() => {
    target.setSelectionRange(0, target.value.length);
    // Small delay added here to account for the fact the user may "drag" their mouse slightly after clicking.
    // This delay ensures that the selected area isn't shorted by their drag area.
    // Note: This solution is not perfect but allows for some "padding" in the users click habits.
  }, 175);
};
