import { Component, Element, Event, EventEmitter, h, Host, Listen, Method, Prop, Watch } from '@stencil/core';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { DomHandler } from '@src/utils/mx-utils/domhandler';

@Component({
  tag: 'mx-modal',
  styleUrl: 'mx-modal.css'
})
export class MxModal {

  /** host element **/
  @Element() hostEl: HTMLMxModalElement;

  /** Boolean value to control if the modal is opened or closed.
   *  Note: Please do not forget to change your local state variable on modalClose & modalOpen events.
   *  These events would be firing any time you change this prop or invoking appropriate methods. */
  @Prop({ mutable: true }) isOpened: boolean = false;
  /** Boolean value to check if the modal closes on overlay. */
  @Prop() readonly closeModalOnOverlayClick?: boolean = false;
  /** Sets the header content Text. */
  @Prop() readonly headercontent: string;
  /** Sets the header icon to the past in kds-icon tag name ex. kds-icon-success */
  @Prop() readonly headerIcon: string = "";
  /** Sets the text of the primary button of the footer. */
  @Prop() readonly footerPrimaryButtonText: string = 'Apply';
  /** Sets whether the primary button is enabled or disabled. It is enabled by default. */
  @Prop() readonly isActivePrimaryButton: boolean = true;
  /** Boolean Value to show or hide the secondary button. */
  @Prop() readonly isActiveSecondaryButton: boolean = false;
  /** Boolean Value to close when the secondary button is clicked. */
  @Prop() readonly closeOnSecondaryButton: boolean = true;
  /** Boolean Value to turn primary button into loading state. */
  @Prop() readonly isLoadingPrimaryButton: boolean = false;
  /** Boolean Value to turn secondary button into loading state. */
  @Prop() readonly isLoadingSecondaryButton: boolean = false;
  /** Boolean Value to turn ternary button into loading state. */
  @Prop() readonly isLoadingTernaryButton: boolean = false;
  /** Sets the text of the secondary footer button. */
  @Prop() readonly footerSecondaryButtonText: string = 'Cancel';
  /** Boolean Value to show or hide the Ternary button. */
  @Prop() readonly isActiveTernaryButton: boolean = false;
  /** Sets the text of the Ternary footer button. */
  @Prop() readonly footerTernaryButtonText: string = 'Reset';
  /** Sets the size of the Modal. */
  @Prop() readonly size: 'large' | 'medium' = 'medium';
  /** Sets the zIndex of the Modal. */
  @Prop() readonly zIndex: string = '500';
  /** Target element to attach the dialog, valid values are "body" or a local html element */
  @Prop() readonly appendTo: string | HTMLElement;
  /** Sets the value of the Primary button kind. */
  @Prop() readonly footerPrimaryButtonKind:
    | 'cancel'
    | 'destructive'
    | 'destructive-inverse'
    | 'destructive-secondary'
    | 'destructive-tertiary'
    | 'favorable'
    | 'favorable-inverse'
    | 'favorable-secondary'
    | 'favorable-tertiary'
    | 'primary'
    | 'primary-inverse'
    | 'secondary'
    | 'secondary-inverse'
    | 'tertiary'
    | 'tertiary-inverse'
    | 'dominant'
    | 'prominent'
    | 'subtle'
    | 'alternate' = 'dominant';

  /** This event is emitted when the user clicks on the primary button.   */
  @Event() applyClick: EventEmitter;
  /** This event is emitted when the user clicks on the secondary button.   */
  @Event() secondaryClick: EventEmitter;
  /** This event is emitted when the user clicks on the ternary button.   */
  @Event() resetClick: EventEmitter;
  /** This event is emitted when the user closes the modal.   */
  @Event() modalClose: EventEmitter;
  /** This event is emitted when the user opens the modal.   */
  @Event() modalOpen: EventEmitter;

  private modalRef: HTMLDivElement;
  private modalOverlayRef: HTMLDivElement;
  private modalWrapperRef: HTMLElement;
  private modalHeaderRef: HTMLMxModalHeaderElement;
  private modalBodyRef: HTMLMxModalBodyElement;

  constructor() {
    if (
      this.footerPrimaryButtonKind.match(
        /^(cancel|destructive|destructive-inverse|destructive-secondary|destructive-tertiary|favorable|favorable-inverse|favorable-secondary|favorable-tertiary|primary|primary-inverse|secondary|secondary-inverse|tertiary|tertiary-inverse|'dominant'|'prominent'|'subtle'|'alternate')$/
      ) === null
    ) {
      this.footerPrimaryButtonKind = 'dominant';
    }
    if (this.size.match(/^(medium|large)$/) === null) {
      this.size = 'medium';
    }
    if (this.footerPrimaryButtonText === '') {
      this.footerPrimaryButtonText = 'Apply';
    }
    if (this.footerSecondaryButtonText === '') {
      this.footerSecondaryButtonText = 'Cancel';
    }
    if (this.footerTernaryButtonText === '') {
      this.footerTernaryButtonText = 'Reset';
    }
  }

  componentDidLoad() {
    this.appendContainer();
    if (this.isOpened) {
      this.modalOverlayRef.classList.add('mx-Modal-overlay--afterOpen');
      this.modalRef.classList.add('mx-Modal--afterOpen');
    }
  }

  @Watch('isOpened')
  updateIsOpened(newValue: boolean) {
    if (newValue) {
      this.modalOverlayRef.classList.add('mx-Modal-overlay--afterOpen');
      this.modalRef.classList.add('mx-Modal--afterOpen');
      this.modalOpen.emit();
    } else {
      this.modalOverlayRef.classList.remove('mx-Modal-overlay--afterOpen');
      this.modalRef.classList.remove('mx-Modal--afterOpen');
      this.modalClose.emit();
      this.scrollToTop();
    }
  }

  /** Creates a modal when called. */
  @Method()
  async createModal() {
    // Makes dialog visible.
    this.isOpened = true;
  }

  /** Dismisses a modal when called. Emits a `modalClose` event. */
  @Method()
  async dismissModal() {
    this.isOpened = false;
  }

  /** Toggle a modal when called. Emits a `modalClose` event when closed. */
  @Method()
  async toggleModal() {
    await (this.isOpened ? this.dismissModal() : this.createModal());
  }

  @Listen('keydown', { target: 'window' })
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key === 'Escape') {
      this.overlayClosed();
      this.isOpened = false;
      this.scrollToTop();
    }
  }

  private readonly scrollToTop = () => {
    this.modalBodyRef.scrollTop = 0;
  };

  // Dynamically builds aria-label using header content.
  private readonly buildLabel = () => {
    return !isNullOrUndefined(this.modalHeaderRef) ? this.modalHeaderRef.textContent.trim() : 'Entering modal';
  };

  //Emits onModalClose event on clicking on overlay
  private overlayClosed = () => {
    if (this.isOpened) {
      this.modalClose.emit();
    }
  };

  private readonly handleOverlayClick = (e) => {
    if (e.target == this.modalOverlayRef && this.closeModalOnOverlayClick) {
      this.modalClose.emit();
      this.isOpened = false;
      this.scrollToTop();
    }
  };

  private readonly appendContainer = () => {
    if (this.appendTo) {
      if (this.appendTo === 'body') {
        const ownerDocument = this.hostEl.ownerDocument;
        ownerDocument.body.appendChild(this.modalWrapperRef);
      } else {
        DomHandler.appendChild(this.modalWrapperRef, this.appendTo);
      }
    }
  };

  private secondaryClickModal() {
    if (this.closeOnSecondaryButton) {
      this.dismissModal();
    }

    this.secondaryClick.emit();
  }

  render() {
    return (
      <Host hidden={!this.isOpened} ref={(el) => (this.modalWrapperRef = el)}>
        <div ref={(el) => (this.modalOverlayRef = el)}
          class={{
            'fixed inset-0 w-full h-full flex justify-center items-center': true,
            'bg-primary-inverse bg-opacity-lessOpaque mx-Modal-overlay': true
          }}
          style={{ zIndex: this.zIndex }}
          id='mx-Modal-overlay'
          role='presentation'
          onClick={this.handleOverlayClick}>
          <div ref={(el) => (this.modalRef = el)}
            aria-modal={this.isOpened}
            class={{
              'bg-primary flex flex-col overflow-hidden rounded-8 mx-Modal': true,
              'mx-Modal--large': this.size === 'large',
              'mx-Modal--medium': this.size === 'medium'
            }}
            id='mx-Modal'
            role='dialog'
            aria-label={this.buildLabel()}
            tabindex='-1'>
            <mx-modal-header ref={(el) => (this.modalHeaderRef = el)}
              headerText={this.headercontent}
              headerIcon={this.headerIcon}
              onDismissalModal={() => this.dismissModal()}
              class={{
                'border-b border-neutral-less-prominent bg-primary mx-modal-header': true,
                'mx-modal-header-large': this.size === 'large',
                'mx-modal-header-medium': this.size === 'medium'
              }} />
            <mx-modal-body ref={(el) => (this.modalBodyRef = el)}
              id='mx-modal-id'
              class={{
                'overflow-auto mx-modal-body': true,
                'mx-modal-body-large': this.size === 'large',
                'mx-modal-body-medium': this.size === 'medium'
              }}
            >
              <slot />
            </mx-modal-body>
            <mx-modal-footer onConfirmFooterClick={this.applyClick.emit}
              onSecondaryFooterClick={() => this.secondaryClickModal()}
              onResetFooterClick={this.resetClick.emit}
              onDismissalModal={() => this.dismissModal()}
              buttonKind={this.footerPrimaryButtonKind}
              isActiveTernaryButton={this.isActiveTernaryButton}
              footerTernaryButtonText={this.footerTernaryButtonText}
              footerSecondaryButtonText={this.footerSecondaryButtonText}
              isActiveSecondaryButton={this.isActiveSecondaryButton}
              footerPrimaryButtonText={this.footerPrimaryButtonText}
              isActivePrimaryButton={this.isActivePrimaryButton}
              isLoadingPrimaryButton={this.isLoadingPrimaryButton}
              isLoadingSecondaryButton={this.isLoadingSecondaryButton}
              isLoadingTernaryButton={this.isLoadingTernaryButton}
              class={{
                'flex justify-end bg-primary mx-modal-footer': true,
                'border-neutral-less-prominent border-t mx-modal-footer-large': this.size === 'large',
                'mx-modal-footer-medium': this.size === 'medium'
              }} />
          </div>
        </div>
      </Host>
    );
  }
}
