import { Component, h, Prop, Host, Event, EventEmitter } from '@stencil/core';
import { iconPrefixElement } from "@src/utils/mx-utils/utils";

@Component({
  tag: 'mx-modal-header',
  styleUrl: 'mx-modal-header.css'
})
export class MxModalHeader {

  /** Sets the header text for the modal. */
  @Prop() readonly headerText: string;
  /** Sets the header icon to the past in kds-icon tag name ex. kds-icon-success */
  @Prop() readonly headerIcon: string;

  /** Dismiss Modal */
  @Event() dismissalModal: EventEmitter;

  render() {
    return (
      <Host>
        <header class='w-full'>
          <slot />
          <div class='flex flex-row justify-between items-center'>
            <span class='font-secondary heading-l overflow-hidden flex items-center self-start
              text-primary mx-header-content'>
              {this.headerIcon && iconPrefixElement(this.headerIcon)}{this.headerText}</span>
            <button
              class='kds-DismissalButton interactive kind-prominent palette-neutral variant-minimal'
              aria-label='Close modal'
              type='button'
              onClick={this.dismissalModal.emit}>
              <kds-icon-close size='s' />
            </button>
          </div>
        </header>
      </Host>
    );
  }
}
