import { Component, Host, h, Event, EventEmitter, Prop } from '@stencil/core';

@Component({
  tag: 'mx-modal-footer',
  styleUrl: 'mx-modal-footer.css'
})
export class MxModalFooter {

  /** Sets the primary button text. */
  @Prop() readonly footerPrimaryButtonText: string;
  /** Sets the button kind. */
  @Prop() readonly buttonKind:
    | 'cancel'
    | 'destructive'
    | 'destructive-inverse'
    | 'destructive-secondary'
    | 'destructive-tertiary'
    | 'favorable'
    | 'favorable-inverse'
    | 'favorable-secondary'
    | 'favorable-tertiary'
    | 'primary'
    | 'primary-inverse'
    | 'secondary'
    | 'secondary-inverse'
    | 'tertiary'
    | 'tertiary-inverse' | 'dominant' | 'prominent' | 'subtle' | 'alternate' = 'dominant';
  /** Sets whether the secondary button is active. */
  @Prop() readonly isActiveSecondaryButton: boolean = false;
  /** Sets the secondary button text. */
  @Prop() readonly footerSecondaryButtonText: string;
  /** Sets whether the ternary button is active. */
  @Prop() readonly isActiveTernaryButton: boolean = false;
  /** Sets the ternary button text. */
  @Prop() readonly footerTernaryButtonText: string;
  /** Sets whether the primary button is enabled or disabled. It is enabled by default. */
  @Prop() readonly isActivePrimaryButton: boolean = true;
  /** Boolean Value to turn primary button into loading state. */
  @Prop() readonly isLoadingPrimaryButton: boolean = false;
  /** Boolean Value to turn secondary button into loading state. */
  @Prop() readonly isLoadingSecondaryButton: boolean = false;
  /** Boolean Value to turn ternary button into loading state. */
  @Prop() readonly isLoadingTernaryButton: boolean = false;
  /** Emits event that confirms the footer has been clicked. */
  @Event() confirmFooterClick: EventEmitter;
  /** Emits event that confirms the secondary footer has been clicked. */
  @Event() secondaryFooterClick: EventEmitter;
  /** Emits event that resets the footer has been reset. */
  @Event() resetFooterClick: EventEmitter;
  /** Dismiss Modal */
  @Event() dismissalModal: EventEmitter;

  render() {
    return (
      <Host>
        <slot />
        <div class='inline-block w-full mx-modal-footer-container'>
          <div class='float-left mx-modal-footer-container-left'>
            <kds-button
              onClick={this.resetFooterClick.emit}
              kind='dominant'
              palette='informative'
              variant='border'
              buttonClass='mx-modal-footer-button'
              indeterminate={this.isLoadingTernaryButton}
              class={{
                hidden: this.isActiveTernaryButton === false
              }}>
              {this.footerTernaryButtonText}
            </kds-button>
          </div>
          <div class='float-right mx-modal-footer-container-right'>
            <kds-button
              onClick={this.secondaryFooterClick.emit}
              kind='dominant'
              palette='neutral'
              variant='border'
              buttonClass='mx-modal-footer-button'
              indeterminate={this.isLoadingSecondaryButton}
              class={{
                hidden: this.isActiveSecondaryButton === false,
                'mr-16': true
              }}>
              {this.footerSecondaryButtonText}
            </kds-button>
            <kds-button
              disabled={!this.isActivePrimaryButton}
              kind={this.buttonKind}
              indeterminate={this.isLoadingPrimaryButton}
              palette='brand'
              onClick={this.confirmFooterClick.emit}
              buttonClass='mx-modal-footer-button'>
              {this.footerPrimaryButtonText}
            </kds-button>
          </div>
        </div>
      </Host>
    );
  }
}
