import { Component, Element, Event, EventEmitter, h, Host, Prop, State, Watch } from '@stencil/core';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { selectAllTextBoxWithDelay } from '@src/utils/mx-utils/mx-input-text-box.utils';

@Component({
  tag: 'mx-none-masked-input',
  styleUrl: 'mx-none-masked-input.css',
  shadow: false
})
export class MxNoneMaskedInput {
  @Element() hostEle: HTMLMxNoneMaskedInputElement;

  /** Sets id of input text box. */
  @Prop() readonly inputId: string;
  /** Sets name of input text box. */
  @Prop() readonly inputName: string;
  /** Sets css class of input text box. */
  @Prop() readonly inputClass: string;
  /** Sets the type of mask for the input. */
  @Prop() readonly mask: string = '';
  /** Provide placeholder text. */
  @Prop() readonly placeholder: string = '';
  /** Sets the maximum length. */
  @Prop() readonly maxLength: number;
  /** Sets input text box's disabled state. */
  @Prop() readonly isDisabled: boolean = false;
  /** Sets whether or not the error message is displayed. */
  @Prop() readonly displayErrorMsg: boolean = false;
  /** Sets whether the input box is compact or not. */
  @Prop() readonly isCompact: boolean = false;
  /** Sets error class in input text box. */
  @Prop({ mutable: true }) hasError = false;
  /** Sets whether or not the input box has an icon. */
  @Prop() readonly hasIcon: boolean = false;
  /** The input's starting value */
  @Prop() readonly value: string = '';
  /** Sets custon prefix for non mask input only  */
  @Prop() readonly customSuffix : string = '';

  /** Enables clearable functionality - shows close icon when value is present */
  @Prop() readonly isClearable: boolean = true;

  /** Enables overtype mode - typing replaces existing content on first keystroke after focus */
  @Prop() readonly isOverType: boolean = false;

  /** Event emitted on input text box when element value changes */
  @Event() inputDataChanged: EventEmitter<string>;

  @State() stateValue: string | number;

  @Watch('value')
  watchStateValue(value) {
    this.stateValue = value;
  }

  constructor() {
    this.stateValue = this.value;
  }

  // Set hasError to false initially(and only the first time).
  // Seems there's a bug with masked-input feeding it the wrong info.
  componentWillLoad() {
    if (this.hasError) {
      this.hasError = false;
    }
  }

  private readonly handleChange = (event: InputEvent) => {
    event.preventDefault();
    const target: HTMLInputElement = event.target as HTMLInputElement;
    this.stateValue = (event.target as HTMLInputElement).value;

    if(this.stateValue.length > 0){
      const val =   this.stateValue.replace(this.customSuffix, '');
      const final = val + this.customSuffix;
      this.stateValue  = final;
    }

    if (this.stateValue === this.customSuffix){
      this.stateValue = '';
    }
    if(!isNullOrUndefinedOrEmptyString(this.customSuffix)){
      this.processInputValue( this.stateValue ,  target);
    }

    this.inputDataChanged.emit(this.stateValue);
  };

  private readonly _onChange = (event: Event) => {
    this.stateValue = (event.target as HTMLInputElement).value;
    this.inputDataChanged.emit(this.stateValue);
  };

  private readonly keyPressHandler = (event: KeyboardEvent) => {
    const target = (event.target as HTMLInputElement);
    this.stateValue = (event.target as HTMLInputElement).value;
    if(!isNullOrUndefinedOrEmptyString(this.customSuffix)){
      this.processInputValue( this.stateValue ,target );
    }

    this.inputDataChanged.emit(this.stateValue);
  };
  private readonly cutEventHandler = (event:ClipboardEvent) => {
    const target = event.target as HTMLInputElement;
    this.stateValue = target.value;
    const remainingCharsLength = this.stateValue.length - this.customSuffix.length;
    if (isNullOrUndefinedOrEmptyString(this.customSuffix)) {
      return;
    }
    if (target.selectionEnd >  remainingCharsLength) {
      event?.preventDefault();
    }
  };
  private readonly keyDownHandler = (event:KeyboardEvent) => {
    const target = event.target as HTMLInputElement;
    this.stateValue = (event.target as HTMLInputElement).value;

    const remainingCharsLength = this.stateValue.length - this.customSuffix.length;

    if (isNullOrUndefinedOrEmptyString(this.customSuffix)) {
      return;
    }

    // prevent backspace and delete
    if ((event?.key === 'Backspace' || event?.key === 'Delete') && target.selectionEnd > remainingCharsLength) {
      event?.preventDefault();
    // prevent suffix from being modified.
    } else if( this.isCharEnteredInSuffix(event, target)) {
      event?.preventDefault();
    }
  };

  private isCharEnteredInSuffix(event, target) {
    if(typeof this.stateValue === 'string' ) {
      const isCharacter = (this.stateValue.includes(this.customSuffix)
          && (/^.$/u.test(event?.key) || event?.key  === "Space"));
      const isInSuffixRange = ( (target.selectionEnd > this.stateValue.length - this.customSuffix.length) &&
          (target.selectionEnd <= this.stateValue.length - 1) );
      return isCharacter && isInSuffixRange;
    } else {
      return false;
    }
  }
  private readonly focusHandler = (event: FocusEvent) => {
    const target: HTMLInputElement = event.target as HTMLInputElement;
    this.stateValue = target.value;

    // For overtype mode, select all text when there's existing content
    if (this.isOverType && this.stateValue && (this.stateValue as string).length > 0) {
      selectAllTextBoxWithDelay(target);
    }
  };

  private readonly processInputValue = (innerValue:string, target?: HTMLInputElement): string => {
    setTimeout(() => {
      if(innerValue.length > 0 && innerValue.endsWith(this.customSuffix)){
        const negativeSelectionStart: number = innerValue.length - this.customSuffix.length;
        target.setSelectionRange(negativeSelectionStart , negativeSelectionStart);
      }
    },5);
    return innerValue;
  };


  render() {
    const showClearIcon = this.isClearable && this.stateValue && (this.stateValue as string).length > 0
        && !this.isDisabled;

    return (
      <Host>
        <div class='textbox-container'>
          <kds-input
            name={this.inputName}
            type='text'
            id={this.inputId}
            inputClass={[
              'mx-input',
              this.inputClass,
              this.hasError || this.displayErrorMsg ? 'border-negative-less-prominent ' : '',
              this.hasIcon ? 'pr-32 relative' : ''
            ].join(' ')}
            value={this.stateValue}
            compact={this.isCompact}
            maxlength={this.maxLength}
            disabled={this.isDisabled}
            placeholder={this.placeholder}
            onInput={this.handleChange}
            onKeyPress={this.keyPressHandler}
            onKeyDown={this.keyDownHandler}
            onChange={this._onChange}
            onCut={this.cutEventHandler}
            onFocusin={this.focusHandler}
          />

          <span class={{
            'mx-icon': true,
            compact: this.isCompact,
            disabled: this.isDisabled
          }}>
            <slot />
            {showClearIcon ? (
              <button
                class='mx-close-icon-btn'
                type='button'
                tabIndex={-1}
                disabled={this.isDisabled}
                onClick={(e) =>
                  this.hostEle.dispatchEvent(
                    new CustomEvent('clearInput', { detail: e, bubbles: true, composed: true })
                  )
                }>
                <kds-icon-close size={'m'} />
              </button>
            ) : (
              <span />
            )}
          </span>
        </div>
      </Host>
    );
  }
}
