import { Component, Host, h, Prop, State, EventEmitter, Event, Element, Watch, Method } from '@stencil/core';
import { eventUtils, stringUtils } from '@src/utils/mx-utils/utils';
import { maskedUtils, selectAllTextBoxWithDelay } from '@src/utils/mx-utils/mx-input-text-box.utils';
@Component({
  tag: 'mx-masked-input',
  styleUrl: 'mx-masked-input.css',
  shadow: false
})
export class MxMaskedInput {
  @Element() hostEl: HTMLMxMaskedInputElement;

  /** Sets name of input text box. */
  @Prop() readonly inputName: string;
  /** Sets css class of input text box. */
  @Prop() readonly inputClass: string;
  /** Sets id of input text box. */
  @Prop() readonly inputId: string;
  /** Sets the mask for the input. */
  @Prop() readonly mask: string = '';
  /** Sets the string that will prepend for the inputted string. */
  @Prop() readonly maskPrefix: string = '';
  /** Determines if the input should behavior as a currency input */
  @Prop() readonly currencyBehavior: boolean = false;
  /** Sets whether or not the error message should be displayed. */
  @Prop() readonly displayError: boolean = false;
  /** Sets whether or not this is a required field. */
  @Prop() readonly required: boolean;
  /** Sets input text box's disabled state. */
  @Prop() readonly disabled: boolean = false;
  /** Sets whether the input box is compact or not. */
  @Prop() readonly compact: boolean = false;
  /** Sets error class in input text box. */
  @Prop() readonly hasError: boolean = false;
  /** The input's starting value */
  @Prop() readonly value: string = '';
  /** The maximum length allowed for the text */
  @Prop() readonly maxLength: number;
  /** Display icon or not. */
  @Prop() readonly hasIcon: boolean = false;
  /** If true then when typing and meet the spec symbol cursor will jump after that spec symbol */
  @Prop() readonly jumpAfterSpecSymbolOnType: boolean = false;
  /** Enables clearable functionality - shows close icon when value is present */
  @Prop() readonly isClearable: boolean = true;
  /** Enables overtype mode - typing replaces existing content on first keystroke after focus */
  @Prop() readonly isOverType: boolean = false;


  @Watch('value')
  watchPropHandler(newValue: string) {
    if (!stringUtils.isBlank(newValue)) {
      this.negative = parseFloat(newValue) < 0;
      this.inputValue = this.processInputValue(newValue, false);
    }
  }

  /** Needed as watch method does not let you clear the inputValue with a blank value, when mask is still in progress.**/
  @Method()
  async clear() {
    this.inputValue = '';
  }

  /** The input's input event */
  @Event() maskedInput: EventEmitter<string>;
  /** The input's change event override */
  @Event() maskedChange: EventEmitter<string>;
  /** The input's blur event override */
  @Event() maskedBlur: EventEmitter<string>;

  /** Stores the input's value */
  @State() inputValue = '';
  /** Stores the input's negative state */
  @State() negative = false;

  componentWillLoad() {
    if (stringUtils.isBlank(this.mask)) {
      return;
    }
    let innerValue: string = this.value;
    if (!stringUtils.isBlank(innerValue)) {
      this.negative = parseFloat(innerValue) < 0;
      if (this.currencyBehavior) {
        innerValue = parseFloat(innerValue).toFixed(2).replace('-', '');
      }
      this.inputValue = this.processInputValue(innerValue, false);
    }
  }

  private readonly keyPressHandler = (e: KeyboardEvent): void => {
    const key: string = e.key;

    const target: HTMLInputElement = e.target as HTMLInputElement;

    if (this.currencyBehavior && key === '-') {
      this.negative = !this.negative;
      this.processInputValue(target.value, true, target);
    }

    if (!maskedUtils.charIsValid(key, target.selectionStart, this.mask) && eventUtils.controlKeys.indexOf(key) < 0) {
      e.preventDefault();
      return;
    }

    const futureValue: string =
      target.value.slice(0, target.selectionStart) + e.key + target.value.slice(target.selectionStart);
    const inputValue: string = this.processInputValue(futureValue, false);

    if (eventUtils.controlKeys.indexOf(key) < 0 && inputValue === this.inputValue) {
      e.preventDefault();
    }

    const isBackSpace: boolean = eventUtils.isBackspace(key);

    if (
      isBackSpace &&
      (target.value === this.maskPrefix + this.mask ||
        (this.currencyBehavior && this.negative && target.value === `${this.maskPrefix}(${this.mask})`))
    ) {
      e.preventDefault();
    }

    if (
      this.currencyBehavior &&
      isBackSpace &&
      this.negative &&
      target.value != null &&
      parseFloat(target.value.replace(this.maskPrefix, '')
        .replace('(', '')
        .replace(')', ''))
        .toFixed(2)
        .startsWith('0.0')
    ) {
      this.negative = false;
    }

    if (!this.currencyBehavior) {
      const innerValue = maskedUtils.replaceMask(target.value, this.mask, this.maskPrefix, false);
      if (isBackSpace && target.selectionStart > innerValue.length && innerValue.length < this.mask.length) {
        target.setSelectionRange(innerValue.length, innerValue.length);
        e.preventDefault();
      }

      if (
        isBackSpace &&
        target.selectionStart >= 1 &&
        maskedUtils.isSpecSymbol(target.value[target.selectionStart - 1])
      ) {
        e.preventDefault();
        target.setSelectionRange(target.selectionStart - 1, target.selectionStart - 1);
      }
    }
  };

  private readonly inputHandler = (e: InputEvent): void => {
    e.preventDefault();
    const target: HTMLInputElement = e.target as HTMLInputElement;
    this.processInputValue(target.value, true, target);
  };

  private readonly focusHandler = (e: FocusEvent): void => {

    // Capture prop values before setTimeout to make them accessible in test environment
    const isOverType = this.isOverType;
    const inputValue = this.inputValue;
    const currencyBehavior = this.currencyBehavior;
    const negative = this.negative;
    const mask = this.mask;
    const maskPrefix = this.maskPrefix;

    const target: HTMLInputElement = e.target as HTMLInputElement;

    // For overtype mode, select all text instead of positioning cursor
    if (isOverType && inputValue && inputValue.length > 0) {
      selectAllTextBoxWithDelay(target);
    } else {
      setTimeout(() => {
        // Normal cursor positioning
        if (currencyBehavior) {
          if (negative) {
            target.setSelectionRange(target.value.length - 1, target.value.length - 1);
          }
        } else {
          const innerValue: string = maskedUtils.replaceMask(target.value, mask, maskPrefix, false);
          if (innerValue.length < target.selectionStart) {
            target.setSelectionRange(innerValue.length, innerValue.length);
          }
        };
      });
    }

  };

  private readonly changeHandler = (): void => {
    const value: string = maskedUtils.replaceMask(this.inputValue, this.mask, this.maskPrefix, this.currencyBehavior);
    this.maskedChange.emit(this.composeValueToEmit(value));
  };

  private readonly blurHandler = (): void => {
    const value: string = maskedUtils.replaceMask(this.inputValue, this.mask, this.maskPrefix, this.currencyBehavior);

    this.maskedBlur.emit(this.composeValueToEmit(value));
  };

  private readonly processInputValue = (
    innerValue: string,
    updateInput = true,
    target?: HTMLInputElement): string => {
    innerValue = maskedUtils.replaceMask(innerValue, this.mask, this.maskPrefix, this.currencyBehavior);

    const specSymbolsAtStart: number = maskedUtils.specSymbolsLengthAtIndex(this.mask, 0);
    const selectionStart: number =
      target == null ? 0 : target.selectionStart + (this.jumpAfterSpecSymbolOnType ? specSymbolsAtStart : 0);

    let inputValue = '';

    if (innerValue.length > 0) {
      if (!this.currencyBehavior) {
        inputValue = this.mask.slice(innerValue.length).padStart(this.mask.length, innerValue);
      } else {
        inputValue =
          this.mask.length >= innerValue.length
            ? this.mask.slice(0, this.mask.length - innerValue.length).padEnd(this.mask.length, innerValue)
            : innerValue;

        inputValue = maskedUtils.fillDivider(inputValue, 3, ',');

        if (this.negative) {
          inputValue = `(${inputValue})`;
        }

        inputValue = this.maskPrefix + inputValue;
      }
    }

    if (updateInput) {
      this.inputValue = inputValue;

      this.maskedInput.emit(this.composeValueToEmit(innerValue));

      // we have to change the position of the cursor but the value of the input is not there yet,
      // so we have to wait until it is there
      setTimeout(() => {
        if (!this.currencyBehavior) {
          let length: number = innerValue.length;
          if (length > selectionStart) {
            if (this.jumpAfterSpecSymbolOnType) {
              length = selectionStart + (maskedUtils.isSpecSymbol(innerValue[selectionStart]) ? 1 : 0);
            } else {
              length =
                selectionStart +
                (maskedUtils.isSpecSymbol(innerValue[selectionStart - 1])
                  ? maskedUtils.specSymbolsLengthAtIndex(this.mask, selectionStart - 1)
                  : 0);
            }
          } else {
            if (this.jumpAfterSpecSymbolOnType) {
              const specSymbolsLengthAtIndex: number = maskedUtils.specSymbolsLengthAtIndex(this.mask, length);
              if (specSymbolsLengthAtIndex > 0) {
                length += specSymbolsLengthAtIndex;
              }
            }
          }
          target.setSelectionRange(length, length);
        } else {
          if (this.negative) {
            const negativeSelectionStart: number = inputValue.length - 1;
            target.setSelectionRange(negativeSelectionStart, negativeSelectionStart);
          }
        }
      }, 5);
    }

    return inputValue;
  };

  private readonly composeValueToEmit = (value): string => {
    if (this.currencyBehavior) {
      if (value.length === 0 || parseFloat(value).toFixed(2) === '0.00') {
        return '0';
      }
      if (this.negative) {
        return `-${value}`;
      }
    }
    return value;
  };

  render() {
    const showClearIcon = this.isClearable && this.inputValue && this.inputValue.length > 0 && !this.disabled;

    return (
      <Host>
        <div class='textbox-container'>
          <kds-input
            type='text'
            name={this.inputName}
            id={this.inputId}
            input-class={[
              'mx-input',
              this.inputClass,
              this.hasError || this.displayError ? 'border-negative-less-prominent ' : '',
              this.hasIcon ? 'pr-32 relative' : ''
            ].join(' ')}
            value={this.inputValue}
            placeholder={this.maskPrefix + this.mask}
            onFocusin={this.focusHandler}
            onKeyPress={this.keyPressHandler}
            onInput={this.inputHandler}
            onChange={this.changeHandler}
            onFocusout={this.blurHandler}
            required={this.required}
            compact={this.compact}
            disabled={this.disabled}
            maxlength={this.maxLength}
          />
          <span class={{
            'mx-icon': true,
            compact: this.compact,
            disabled: this.disabled
          }}>
            <slot />
            {showClearIcon ? (

              <button
                class='mx-close-icon-btn'
                type='button'
                tabIndex={-1}
                disabled={this.disabled}
                onClick={(e) => {
                  this.clear();
                  this.hostEl.dispatchEvent(
                    new CustomEvent('clearInput', { detail: e, bubbles: true, composed: true })
                  );
                }
                }>
                <kds-icon-close size='m'/>
              </button>

            ) : (
              <span/>
            )}
          </span>
        </div>

      </Host>
    );
  }
}
