import { Component, Element, h, Host, Listen, Method, Prop, State, Watch } from '@stencil/core';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { ErrorMessage, InputMaskType } from './mx-input-text-box.model';

@Component({
  tag: 'mx-input-text-box',
  styleUrl: 'mx-input-text-box.css',
  shadow: false
})
export class MxInputTextBox {
  @Element() hostEl: HTMLMxInputTextBoxElement;
  /** Sets id of input text box. */
  @Prop() readonly inputId: string;
  /** Sets name of input text box. */
  @Prop() readonly inputName: string;
  /** Sets input text box's disabled state. */
  @Prop() readonly isDisabled: boolean = false;
  /** Sets error class in input text box. */
  @Prop() readonly hasError: boolean = false;
  /** Sets whether the input box is compact or not. */
  @Prop() readonly isCompact: boolean = false;
  /** Displays theoptionalText next to the label. */
  @Prop() readonly displayOptionalText: boolean = false;
  /** Sets optional text when input text box is optional, defaults to "Optional". */
  @Prop() readonly optionalText: string = '';
  /** Sets the type of mask for the input. */
  @Prop() readonly mask: InputMaskType = InputMaskType.NONE;
  /** Sets text to provide additional information (below the text content). */
  @Prop() readonly hintText: string;
  /** Sets visible label text. */
  @Prop() readonly label: string;
  /** Provide placeholder text. */
  @Prop() readonly placeholder: string = '';
  /** The input's starting value */
  @Prop({ mutable: true }) value: string | number;
  /** Show or hide value under the input box **/
  @Prop() readonly showValue: boolean = false;
  /** Sets custon prefix for non mask input only  */
  @Prop() readonly customSuffix : string = '';

  // extra props for input text box
  /** Sets the maximum length. */
  @Prop() readonly maxLength: number;
  /** Sets whether the input has an icon or not. */
  @Prop() readonly hasIcon: boolean = false;
  /** Sets name of input text box. */
  @Prop({ reflect: true }) readonly name: string;
  /**Sets custom error message  */
  @Prop() readonly customErrorMessage: string;
  /** Enables clearable functionality - shows close icon when value is present */
  @Prop() readonly isClearable: boolean = true;
  /** Enables Over Type mode - typing replaces existing content on first keystroke after focus */
  @Prop() readonly isOverType: boolean = false;

  /** Sets the error message text that should be displayed. */
  private readonly errorMessage = ErrorMessage;

  @State() errorText: string;
  @State() displayErrorMsg: boolean = this.hasError;
  @State() stateValue: string | number;


  @Watch('value')
  handleValueChange(newValue) {
    this.stateValue = newValue;
  }

  @Watch('stateValue')
  handleStateValueChange(newValue) {
    this.value = newValue;
  }

  @Listen('clearInput')
  async clearInputHandler() {
    this.stateValue = '';
    this.value = '';
    await this.setFocus();
  }

  /** Sets focus on the input. */
  @Method()
  async setFocus() {
    const inputComponent: HTMLElement = this.hostEl.querySelector('.mx-input');
    if (!isNullOrUndefined(inputComponent)) {
      inputComponent.focus();
    }
  }

  /** Sets the input to blur. */
  @Method()
  async setBlur() {
    const inputComponent: HTMLElement = this.hostEl.querySelector('.mx-input');
    if (!isNullOrUndefined(inputComponent)) {
      inputComponent.blur();
    }
  }

  constructor() {
    this.stateValue = this.value;
    if (isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
      switch (this.mask) {
        case InputMaskType.PHONE_NUMBER:
          this.errorText = this.errorMessage.PHONE_NUMBER;
          break;
        case InputMaskType.DATE:
          this.errorText = this.errorMessage.DATE;
          break;
        case InputMaskType.ZIPCODE:
          this.errorText = this.errorMessage.ZIPCODE;
          break;
        case InputMaskType.NONE:
          this.errorText = this.errorMessage.NONE;
          break;
        default:
          break;
      }
    } else {
      this.errorText = this.customErrorMessage;
    }
  }

  @Listen('inputDataChanged')
  inputDataChangedHandler(dataFromChild) {
    this.stateValue = dataFromChild.detail;
  }


  // Need both watchers because the customErrorMessage may be set at the same time hasError is changed.
  @Watch('customErrorMessage')
  @Watch('hasError')
  hasErrorChange() {
    // Determine the correct error message.
    if (this.hasError) {

      this.displayErrorMsg = true;
      if (isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
        switch (this.mask) {
          case InputMaskType.PHONE_NUMBER:
            this.errorText = this.errorMessage.PHONE_NUMBER;
            break;
          case InputMaskType.DATE:
            this.errorText = this.errorMessage.DATE;
            break;
          case InputMaskType.ZIPCODE:
            this.errorText = this.errorMessage.ZIPCODE;
            break;
          case InputMaskType.NONE:
            this.errorText = this.errorMessage.NONE;
            break;
          default:
            break;
        }
      } else {
        this.errorText = this.customErrorMessage;
      }
    } else {
      this.displayErrorMsg = false;
    }
  }

  private validateMaskInput(event: Event) {
    switch (this.mask) {
      case InputMaskType.PHONE_NUMBER:
        this.validatePhoneNumber(event as CustomEvent);
        break;
      case InputMaskType.DATE:
        this.validateDate(event as CustomEvent);
        break;
      case InputMaskType.ZIPCODE:
        this.validateZipcode(event as CustomEvent);
        break;
      case InputMaskType.CURRENCY:
        this.validateCurrency(event);
        break;
      case InputMaskType.NONE:
        this.validateNoneMaskInput(event);
        break;
      default:
        break;
    }
  }

  private validateZipcode(event: CustomEvent) {
    this.stateValue = event.detail;
    if ((this.stateValue as string).length < 5) {
      this.displayErrorMsg = true;
      this.stateValue = '';
      if (!isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
        this.errorText = this.customErrorMessage;
      } else {
        this.errorText = this.errorMessage.ZIPCODE;
      }
    }
  }

  private validateDate(event: CustomEvent) {
    this.stateValue = event.detail;
    if ((this.stateValue as string).length < 10) {
      this.displayErrorMsg = true;
      this.stateValue = '';
      if (!isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
        this.errorText = this.customErrorMessage;
      } else {
        this.errorText = this.errorMessage.DATE;
      }
    }
  }

  private validatePhoneNumber(event: CustomEvent) {
    this.stateValue = event.detail;
    if ((this.stateValue as string).length < 14) {
      this.displayErrorMsg = true;
      this.stateValue = '';
      if (!isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
        this.errorText = this.customErrorMessage;
      } else {
        this.errorText = this.errorMessage.PHONE_NUMBER;
      }

    }
  }

  private validateCurrency(event: Event) {
    this.stateValue = (event.target as HTMLInputElement).value;
    if (this.hasError && !isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
      this.displayErrorMsg = true;
      this.stateValue = '';
      this.errorText = this.customErrorMessage;
    }
  }

  private validateNoneMaskInput(event: Event) {
    this.stateValue = (event.target as HTMLInputElement).value;
    if (this.stateValue.length === 0 && this.hasError) {
      this.displayErrorMsg = true;
      this.stateValue = '';
      if (!isNullOrUndefinedOrEmptyString(this.customErrorMessage)) {
        this.errorText = this.customErrorMessage;
      } else {
        this.errorText = this.errorMessage.NONE;
      }
    }
  }



  private readonly _onBlur = (event: FocusEvent | CustomEvent) => {
    this.validateMaskInput(event);
  };

  private readonly _onFocus = () => {
    this.displayErrorMsg = false;
  };

  private readonly _onChange = (event: Event) => {
    this.validateMaskInput(event);
  };

  private readonly _onMaskedInput = (event: CustomEvent) => {
    this.stateValue = event.detail;
  };

  render() {
    return (
      <Host>
        <div
          class={{
            'mx-input-text-container': true,
            'text-negative-less-prominent': this.displayErrorMsg
          }}>

          {this.label && (
            <kds-label class={{ 'mb-4 mx-label': true, 'text-negative-less-prominent': this.displayErrorMsg }}>
              {this.label}
              {this.displayOptionalText && (
                <span class={{
                  'optional-text': true,
                  'text-secondary': !this.displayErrorMsg,
                  'text-negative-less-prominent': this.displayErrorMsg
                }}>
                  ({this.optionalText})
                </span>
              )}
            </kds-label>
          )}

          {this.mask === InputMaskType.ZIPCODE ? (
            <mx-masked-input
              input-name={this.inputName}
              input-class='mx-input-text-box'
              mask='_____'
              inputId={this.inputId}
              value={this.stateValue as string}
              disabled={this.isDisabled}
              hasError={this.hasError}
              hasIcon={this.hasIcon || this.isClearable}
              isOverType={this.isOverType}
              displayError={this.displayErrorMsg}
              compact={this.isCompact}
              onMaskedInput={this._onMaskedInput}
              onFocusin={this._onFocus}
              onMaskedBlur={this._onBlur}
              onMaskedChange={this._onChange}
              isClearable={this.isClearable}>
              <slot />
            </mx-masked-input>
          ) : this.mask === InputMaskType.CURRENCY ? (
            <mx-masked-input
              input-name={this.inputName}
              input-class='mx-input-text-box'
              mask='0.00'
              maskPrefix='$ '
              currencyBehavior={true}
              inputId={this.inputId}
              value={this.stateValue as string}
              hasError={this.hasError}
              isOverType={this.isOverType}
              hasIcon={this.hasIcon || this.isClearable}
              disabled={this.isDisabled}
              compact={this.isCompact}
              onMaskedInput={this._onMaskedInput}
              onFocusin={this._onFocus}
              onMaskedBlur={this._onBlur}
              onMaskedChange={this._onChange}
              isClearable={this.isClearable}>
              <slot />
            </mx-masked-input>
          ) : this.mask === InputMaskType.DATE ? (
            <mx-masked-input
              input-name={this.inputName}
              input-class='mx-input-text-box'
              mask='MM/DD/YYYY'
              inputId={this.inputId}
              value={this.stateValue as string}
              disabled={this.isDisabled}
              hasError={this.hasError}
              isOverType={this.isOverType}
              hasIcon={this.hasIcon || this.isClearable}
              compact={this.isCompact}
              displayError={this.displayErrorMsg}
              onMaskedInput={this._onMaskedInput}
              onFocusin={this._onFocus}
              onMaskedBlur={this._onBlur}
              onMaskedChange={this._onChange}
              isClearable={this.isClearable}>
              <slot />
            </mx-masked-input>
          ) : this.mask === InputMaskType.PHONE_NUMBER ? (
            <mx-masked-input
              input-name={this.inputName}
              input-class='mx-input-text-box'
              mask='(___) ___-____'
              inputId={this.inputId}
              value={this.stateValue as string}
              disabled={this.isDisabled}
              hasError={this.hasError}
              hasIcon={this.hasIcon || this.isClearable}
              compact={this.isCompact}
              isOverType={this.isOverType}
              displayError={this.displayErrorMsg}
              onMaskedInput={this._onMaskedInput}
              onFocusin={this._onFocus}
              onMaskedBlur={this._onBlur}
              onMaskedChange={this._onChange}
              isClearable={this.isClearable}>
              <slot />
            </mx-masked-input>
          ) : this.mask === InputMaskType.NONE ? (
            <mx-none-masked-input
              input-name={this.inputName}
              input-class='mx-input-text-box'
              inputId={this.inputId}
              value={this.stateValue as string}
              isDisabled={this.isDisabled}
              hasError={this.hasError}
              isOverType={this.isOverType}
              maxLength={this.maxLength}
              hasIcon={this.hasIcon || this.isClearable}
              isCompact={this.isCompact}
              placeholder={this.placeholder}
              displayErrorMsg={this.displayErrorMsg}
              customSuffix={this.customSuffix}
              onFocusin={this._onFocus}
              onFocusout={this._onBlur}
              onChange={this._onChange}
              isClearable={this.isClearable}>
              <slot />
            </mx-none-masked-input>
          ) : (
            <span />
          )}
          {this.showValue && (
            <kds-text>Value: {this.stateValue}</kds-text>
          )}

          {!isNullOrUndefinedOrEmptyString(this.hintText) && (
            <div class='mx-hint-text py-8 body-m'>{this.hintText}</div>
          )}

          {this.displayErrorMsg && (
            <div class='text-negative-less-prominent mt-8 body-m'>{this.errorText}</div>
          )}
        </div>
      </Host>
    );
  }
}
